import "@/App.css";
import {
  BrowserRouter,
  Routes,
  Route,
  Navigate,
  useLocation,
  Outlet,
} from "react-router-dom";

import axios from "axios";
import { Toaster } from "@/components/ui/sonner";

import { useEffect, useState } from "react";

// ======================
// PUBLIC PAGES
// ======================
import LandingPage from "@/pages/LandingPage";
import SchoolProfilePage from "@/pages/SchoolProfilePage";

// ======================
// AUTH PAGES
// ======================
import LoginPage from "@/pages/LoginPage";
import RegisterPage from "@/pages/RegisterPage";
import JoinSchoolPage from "@/pages/JoinSchoolPage";

// ======================
// DASHBOARD LAYOUT
// ======================
import DashboardLayout from "@/components/layouts/DashboardLayout";

// ======================
// CORE MODULES
// ======================
import Dashboard from "@/pages/Dashboard";
import StudentsPage from "@/pages/StudentsPage";
import StaffPage from "@/pages/StaffPage";
import FeesPage from "@/pages/FeesPage";
import AttendancePage from "@/pages/AttendancePage";
import ExamsPage from "@/pages/ExamsPage";
import TimetablePage from "@/pages/TimetablePage";
import InventoryPage from "@/pages/InventoryPage";

// ======================
// PORTALS
// ======================
import StudentPortal from "@/pages/StudentPortal";
import TeacherPortal from "@/pages/TeacherPortal";
import FinancePortal from "@/pages/FinancePortal";
import SecretaryPortal from "@/pages/SecretaryPortal";

// ======================
// ADMIN
// ======================
import SuperAdminDashboard from "@/pages/SuperAdminDashboard";
import AnnouncementsPage from "@/pages/AnnouncementsPage";

// ======================
// DEBUG
// ======================
import DataExplorer from "@/pages/DataExplorer";

// ======================
// BACKEND CONFIG
// ======================
const BACKEND_URL =
  process.env.REACT_APP_BACKEND_URL || "http://localhost:8000";

export const API = `${BACKEND_URL.replace(/\/$/, "")}/api`;

// ======================
// ROLE NORMALIZER
// ======================
export const normalizeRole = (role) => {
  if (!role) return "";

  const r = String(role).trim().toLowerCase();

  const roleMap = {
    admin: "SCHOOL_ADMIN",
    schooladmin: "SCHOOL_ADMIN",
    school_admin: "SCHOOL_ADMIN",

    superadmin: "SUPER_ADMIN",
    super_admin: "SUPER_ADMIN",

    teacher: "TEACHER",
    finance: "FINANCE",
    secretary: "SECRETARY",

    student: "STUDENT",
    parent: "STUDENT",
  };

  return roleMap[r] || r.toUpperCase();
};

// ======================
// AUTH SERVICE
// ======================
export const authService = {
  getToken: () => {
    try {
      return localStorage.getItem("token");
    } catch {
      return null;
    }
  },

  getUser: () => {
    try {
      const user = localStorage.getItem("user");

      if (!user || user === "undefined") {
        return null;
      }

      const parsedUser = JSON.parse(user);

      return {
        ...parsedUser,
        role: normalizeRole(parsedUser?.role),
      };
    } catch (error) {
      console.error("Failed to parse user:", error);
      return null;
    }
  },

  setAuth: (token, user) => {
    if (!token || !user) return;

    const normalizedUser = {
      ...user,
      role: normalizeRole(user?.role),
    };

    localStorage.setItem("token", String(token));
    localStorage.setItem(
      "user",
      JSON.stringify(normalizedUser)
    );

    // GLOBAL AUTH SYNC
    window.dispatchEvent(new Event("auth-change"));
  },

  clearAuth: () => {
    localStorage.removeItem("token");
    localStorage.removeItem("user");

    // GLOBAL AUTH SYNC
    window.dispatchEvent(new Event("auth-change"));
  },

  isAuthenticated: () => {
    return !!authService.getToken();
  },

  getRole: () => {
    const user = authService.getUser();

    if (!user?.role) return null;

    return normalizeRole(user.role);
  },
};

// ======================
// AXIOS CLIENT
// ======================
export const apiClient = axios.create({
  baseURL: API,
  timeout: 30000,
});

// ======================
// REQUEST INTERCEPTOR
// ======================
apiClient.interceptors.request.use(
  (config) => {
    const token = authService.getToken();

    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }

    config.headers["Content-Type"] = "application/json";

    return config;
  },
  (error) => Promise.reject(error)
);

// ======================
// RESPONSE INTERCEPTOR
// ======================
apiClient.interceptors.response.use(
  (response) => response,

  (error) => {
    const status = error?.response?.status;

    // AUTO LOGOUT
    if (status === 401) {
      authService.clearAuth();

      if (window.location.pathname !== "/login") {
        window.location.href = "/login";
      }
    }

    console.error("API ERROR:", {
      url: error?.config?.url,
      method: error?.config?.method,
      status,
      data: error?.response?.data,
    });

    return Promise.reject(error);
  }
);

// ======================
// DEFAULT ROUTES
// ======================
const getDefaultRouteByRole = (role) => {
  const normalized = normalizeRole(role);

  switch (normalized) {
    case "SUPER_ADMIN":
      return "/app/super-admin";

    case "SCHOOL_ADMIN":
      return "/app/dashboard";

    case "TEACHER":
      return "/app/teacher-portal";

    case "FINANCE":
      return "/app/finance-portal";

    case "SECRETARY":
      return "/app/secretary-portal";

    case "STUDENT":
      return "/app/student-portal";

    default:
      return "/login";
  }
};

// ======================
// ROUTE PERMISSIONS
// ======================
const routePermissions = {
  dashboard: [
    "SUPER_ADMIN",
    "SCHOOL_ADMIN",
    "TEACHER",
    "FINANCE",
    "SECRETARY",
  ],

  students: [
    "SCHOOL_ADMIN",
    "SECRETARY",
    "TEACHER",
  ],

  staff: [
    "SUPER_ADMIN",
    "SCHOOL_ADMIN",
  ],

  fees: [
    "SCHOOL_ADMIN",
    "FINANCE",
  ],

  attendance: [
    "SCHOOL_ADMIN",
    "TEACHER",
    "SECRETARY",
  ],

  exams: [
    "SCHOOL_ADMIN",
    "TEACHER",
  ],

  timetable: [
    "SCHOOL_ADMIN",
    "TEACHER",
    "STUDENT",
  ],

  inventory: [
    "SCHOOL_ADMIN",
    "SECRETARY",
  ],

  announcements: [
    "SCHOOL_ADMIN",
    "SECRETARY",
    "TEACHER",
    "FINANCE",
    "STUDENT",
  ],

  "teacher-portal": [
    "TEACHER",
    "SCHOOL_ADMIN",
  ],

  "finance-portal": [
    "FINANCE",
    "SCHOOL_ADMIN",
  ],

  "secretary-portal": [
    "SECRETARY",
    "SCHOOL_ADMIN",
  ],

  "student-portal": [
    "STUDENT",
  ],

  "super-admin": [
    "SUPER_ADMIN",
  ],

  debug: [
    "SUPER_ADMIN",
    "SCHOOL_ADMIN",
  ],
};

// ======================
// PROTECTED ROUTE
// ======================
const ProtectedRoute = () => {
  const token = authService.getToken();

  if (!token) {
    return <Navigate to="/login" replace />;
  }

  return <Outlet />;
};

// ======================
// ROLE PROTECTED ROUTE
// ======================
const RoleProtectedRoute = ({
  routeKey,
  children,
}) => {
  const user = authService.getUser();

  if (!user) {
    return <Navigate to="/login" replace />;
  }

  const role = normalizeRole(user.role);

  const allowedRoles =
    routePermissions[routeKey] || [];

  // HARD BLOCK
  if (!allowedRoles.includes(role)) {
    return (
      <Navigate
        to={getDefaultRouteByRole(role)}
        replace
      />
    );
  }

  return children;
};

// ======================
// ROOT REDIRECT
// ======================
const AppRootRedirect = () => {
  const [role, setRole] = useState(null);

  useEffect(() => {
    setRole(authService.getRole());
  }, []);

  if (role === null) return null;

  return (
    <Navigate
      to={getDefaultRouteByRole(role)}
      replace
    />
  );
};

// ======================
// SAFE LAYOUT
// ======================
const SafeDashboardLayout = () => {
  const location = useLocation();

  const [authState, setAuthState] = useState({
    user: authService.getUser(),
    token: authService.getToken(),
  });

  useEffect(() => {
    const syncAuth = () => {
      setAuthState({
        user: authService.getUser(),
        token: authService.getToken(),
      });
    };

    // INTERNAL AUTH CHANGE
    window.addEventListener(
      "auth-change",
      syncAuth
    );

    // CROSS TAB AUTH CHANGE
    window.addEventListener(
      "storage",
      syncAuth
    );

    return () => {
      window.removeEventListener(
        "auth-change",
        syncAuth
      );

      window.removeEventListener(
        "storage",
        syncAuth
      );
    };
  }, []);

  const { user, token } = authState;

  // HARD AUTH CHECK
  if (!user || !token) {
    authService.clearAuth();

    return (
      <Navigate
        to="/login"
        replace
      />
    );
  }

  return (
    <DashboardLayout
      key={`${location.pathname}-${user?.role}`}
    />
  );
};

// ======================
// APP
// ======================
function App() {
  return (
    <div className="App">
      <BrowserRouter>

        <Routes>

          {/* ========================= */}
          {/* PUBLIC ROUTES */}
          {/* ========================= */}

          <Route
            path="/"
            element={<LandingPage />}
          />

          <Route
            path="/login"
            element={<LoginPage />}
          />

          <Route
            path="/register"
            element={<RegisterPage />}
          />

          <Route
            path="/register-school"
            element={<RegisterPage />}
          />

          <Route
            path="/setup-school"
            element={<SchoolProfilePage />}
          />

          <Route
            path="/join-school"
            element={<JoinSchoolPage />}
          />

          <Route
            path="/join/:inviteCode"
            element={<JoinSchoolPage />}
          />

          {/* ========================= */}
          {/* PROTECTED APP */}
          {/* ========================= */}

          <Route element={<ProtectedRoute />}>

            <Route
              path="/app"
              element={<SafeDashboardLayout />}
            >

              {/* ROOT AUTO REDIRECT */}
              <Route
                index
                element={<AppRootRedirect />}
              />

              {/* DASHBOARD */}
              <Route
                path="dashboard"
                element={
                  <RoleProtectedRoute routeKey="dashboard">
                    <Dashboard />
                  </RoleProtectedRoute>
                }
              />

              {/* STUDENTS */}
              <Route
                path="students"
                element={
                  <RoleProtectedRoute routeKey="students">
                    <StudentsPage />
                  </RoleProtectedRoute>
                }
              />

              {/* STAFF */}
              <Route
                path="staff"
                element={
                  <RoleProtectedRoute routeKey="staff">
                    <StaffPage />
                  </RoleProtectedRoute>
                }
              />

              {/* FEES */}
              <Route
                path="fees"
                element={
                  <RoleProtectedRoute routeKey="fees">
                    <FeesPage />
                  </RoleProtectedRoute>
                }
              />

              {/* ATTENDANCE */}
              <Route
                path="attendance"
                element={
                  <RoleProtectedRoute routeKey="attendance">
                    <AttendancePage />
                  </RoleProtectedRoute>
                }
              />

              {/* EXAMS */}
              <Route
                path="exams"
                element={
                  <RoleProtectedRoute routeKey="exams">
                    <ExamsPage />
                  </RoleProtectedRoute>
                }
              />

              {/* TIMETABLE */}
              <Route
                path="timetable"
                element={
                  <RoleProtectedRoute routeKey="timetable">
                    <TimetablePage />
                  </RoleProtectedRoute>
                }
              />

              {/* INVENTORY */}
              <Route
                path="inventory"
                element={
